import React, { useState } from "react";
import { sendChat } from "../api/apiService";

function ChatBot() {
  const [message, setMessage] = useState("");
  const [messages, setMessages] = useState([]);
  const [loading, setLoading] = useState(false);

  const handleSend = async () => {
    if (!message.trim()) return;

    // user message
    const userMsg = { type: "user", text: message };
    setMessages((prev) => [...prev, userMsg]);

    setLoading(true);

    try {
      const res = await sendChat(message);

      console.log("CHAT RESPONSE:", res);

      // ✅ FIX (handle multiple response formats)
      const botMsg = {
        type: "bot",
        text: res?.reply || res?.message || res?.data || "No response",
      };

      setMessages((prev) => [...prev, botMsg]);

    } catch (err) {
      console.error("CHAT ERROR:", err);

      setMessages((prev) => [
        ...prev,
        { type: "bot", text: "Server error ❌" },
      ]);
    }

    setLoading(false);
    setMessage("");
  };

  return (
    <div>
      <h2>🤖 AI Chat</h2>

      {/* CHAT BOX */}
      <div
        style={{
          border: "1px solid #ccc",
          padding: "10px",
          minHeight: "200px",
          marginBottom: "10px",
        }}
      >
        {messages.length === 0 && <p>Start chatting...</p>}

        {messages.map((msg, i) => (
          <p key={i}>
            <b>{msg.type === "user" ? "You" : "Bot"}:</b> {msg.text}
          </p>
        ))}

        {loading && <p>Bot is typing...</p>}
      </div>

      {/* INPUT */}
      <input
        value={message}
        onChange={(e) => setMessage(e.target.value)}
        placeholder="Ask something..."
        onKeyDown={(e) => e.key === "Enter" && handleSend()} // ✅ Enter key support
      />

      <button onClick={handleSend} disabled={loading}>
        {loading ? "Sending..." : "Send"}
      </button>
    </div>
  );
}

export default ChatBot;
